// // This module compares two 4-bit inputs and outputs whether they are not equal, with the first being less than or equal to the second.
module top_module(
    input [3:0] in0,
    input [3:0] in1,
    output reg eq,
    output reg gt,
    output reg lt
);always @(*) begin
        eq = (in0 == in1);
        gt = (in0 > in1);
        lt = (in0 < in1);
    end

endmodule
